// Filter out WhatsApp status updates (delivered/read/sent notifications)
const messages = $json.messages;
if (!messages || messages.length === 0) {
  return [];
}

const message = messages[0];

// FIX 2: Detect message type for non-text handling
const messageType = message.type ||
  (message.text ? 'text' :
   message.audio ? 'audio' :
   message.voice ? 'audio' :
   message.image ? 'image' :
   message.video ? 'video' :
   message.sticker ? 'sticker' :
   message.document ? 'document' :
   message.location ? 'location' :
   message.contacts ? 'contacts' :
   'unknown');

// Image/video with caption counts as text
const hasCaption = !!(message.caption?.body || message.image?.caption || message.video?.caption);
const isNonText = !hasCaption && ['audio', 'voice', 'sticker', 'document', 'location', 'contacts'].includes(messageType);

const textContent = message.caption?.body || message.image?.caption || message.video?.caption || message.text?.body || '';

return {
  json: {
    phone: (message.from || '').replace(/[^0-9]/g, ''),
    text: textContent,
    messageId: message.id || '',
    timestamp: new Date().toISOString(),
    messageType: messageType,
    isNonText: isNonText,
    audioId: (messageType === 'audio') ? (message.audio?.id || message.voice?.id || '') : ''
  }
};

// OpenAI API key (n8n Code nodes cannot use getCredentials)
const OPENAI_KEY = 'REDACTED_USE_N8N_CREDENTIALS';
const ctx = $input.first().json;

// --- Helper: sleep for retry backoff ---
function sleep(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }

// --- Helper: call OpenAI with given messages ---
async function callOpenAI(messages, maxTokens) {
  return await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${OPENAI_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'gpt-4o-mini',
      messages,
      temperature: 0.8,
      max_tokens: maxTokens,
      response_format: { type: "json_object" }
    },
    json: true
  });
}

try {
  // Include timestamps in history messages for time awareness
  const historyMessages = (ctx.conversation_history || [])
    .filter(m => m && m.role && m.content)
    .map(m => {
      const ts = m.timestamp ? `[${m.timestamp}] ` : '';
      return { role: m.role, content: ts + m.content };
    });

  // Calculate gap text for system prompt
  const gapMinutes = ctx.last_interaction_gap_minutes;
  let gapText = 'Primeira interacao';
  let isStaleConversation = false;
  if (gapMinutes !== null) {
    if (gapMinutes < 5) gapText = 'Agora mesmo (menos de 5 min)';
    else if (gapMinutes < 60) gapText = gapMinutes + ' minutos atras';
    else if (gapMinutes < 1440) {
      const h = Math.floor(gapMinutes / 60);
      gapText = h + ' hora' + (h > 1 ? 's' : '') + ' atras';
    } else {
      const d = Math.floor(gapMinutes / 1440);
      gapText = d + ' dia' + (d > 1 ? 's' : '') + ' atras';
    }
    isStaleConversation = gapMinutes >= 360; // 6 hours
  }

  const modoTesteSection = !ctx.user_registered ? `
  MODO TESTE - VERSAO LIMITADA:
  Voce esta conversando com um usuario em MODO TESTE da Foquinha.
  LIMITACOES: NAO pode criar/editar/gerenciar habitos. Pode APENAS conversar e dar consultoria.
  Na primeira mensagem, apresente-se e explique gentilmente que e uma versao teste.
  Incentive a conhecer a versao completa. Nao mencione "Bora" - fale sobre "Foquinha".
  ` : '';

  const pendingSection = ctx.pending_state.action ? `ESTADO PENDENTE:
  - Acao: ${ctx.pending_state.action} | Dados: ${JSON.stringify(ctx.pending_state.data)} | Aguardando: ${ctx.pending_state.awaiting}
  (Complete a acao quando o usuario fornecer o que falta)` : '';

  const stalePendingWarning = (ctx.pending_state.action && isStaleConversation) ?
    `ATENCAO: Estado pendente EXPIRADO (>6h). NAO retome automaticamente. Limpe: new_state.pending_action = null.` : '';

  const staleConversationNote = isStaleConversation ?
    `NOTA: >6h desde ultima msg. Trate como conversa nova. Cumprimente naturalmente.` : '';

  // --- Task #19: Conditionally include templates section ---
  const includeTemplates = ctx.wants_create_habit;

  const templatesSection = includeTemplates ? `
  HABITOS POPULARES PARA SUGERIR:
  ${ctx.templates_context}` : '';

  // --- Build creation rules only when relevant ---
  const creationRules = ctx.user_registered ? `
  REGRAS PARA CRIAR HABITO/TAREFA:
  - Nome + horario fornecidos (ex: "tomar whey as 20") = use "create_habit" IMEDIATAMENTE. NAO peca confirmacao.
  - Nome sem horario = pergunte UMA VEZ o horario.
  - Deduza periodo do horario: <12=morning, 12-18=afternoon, >18=evening.
  - Converta horarios: "7h"="07:00", "3 da tarde"="15:00", "meia noite"="00:00", "20"="20:00".
  - Sem horario = padrao do periodo: morning=07:00, afternoon=13:00, evening=19:00.
  - "reuniao quinta" ou "entregar relatorio dia 25" = TAREFA PONTUAL (frequency_type:"once", due_date obrigatorio).
  - Recorrente: frequency_type:"daily", days_of_week:[0,1,2,3,4,5,6].
  - Dias especificos: frequency_type:"fixed_days", days_of_week conforme MAPEAMENTO OBRIGATORIO abaixo.
  MAPEAMENTO DIAS (NUNCA erre): 0=Domingo, 1=Segunda, 2=Terca, 3=Quarta, 4=Quinta, 5=Sexta, 6=Sabado
  EXEMPLOS: "segunda"->[1], "terca"->[2], "quarta"->[3], "quinta"->[4], "sexta"->[5], "sabado"->[6], "domingo"->[0]
  "seg a sex"->[1,2,3,4,5] | "fim de semana"->[0,6] | "seg,qua,sex"->[1,3,5] | "todo dia"->[0,1,2,3,4,5,6]
  NUNCA use 0 para segunda! 0=DOMINGO.

  DUPLICATAS - REGRA ESTRITA:
  - So considere duplicata se o nome for IDENTICO (ex: "Correr" e "Correr").
  - "Academia" != "Correr", "Yoga" != "Meditar" — atividades diferentes NAO sao duplicatas!
  - Na duvida, CRIE. E melhor ter 2 similares do que perder um pedido.

  LIMITACAO - 1 HORARIO POR HABITO:
  O sistema suporta APENAS 1 reminder_time por habito.
  Se usuario pedir horarios diferentes em dias diferentes (ex: "seg 17h e sab 6h"):
  - EXPLIQUE: "Como os horarios sao diferentes, vou criar 2 lembretes separados!"
  - CRIE 2 habitos: "Correr (seg/qua)" reminder_time="17:00" days_of_week=[1,3] e "Correr (sab)" reminder_time="06:00" days_of_week=[6]
  - NUNCA diga que configurou 2 horarios no mesmo habito.

  CONFIRMACAO OBRIGATORIA quando:
  - Multiplos dias com horarios DIFERENTES na mesma mensagem
  - Mais de 1 atividade diferente na mesma mensagem
  Formato: "Vou criar assim:\n[lista dos habitos]\nTa certo?"` : '';

  const systemPrompt = `Voce e o Foquinha, assistente pessoal de habitos.
  Amigavel, empatico, motivador. Conversa como amigo/coach. Emojis com moderacao.
  ${modoTesteSection}
  DATA: ${ctx.today_date} (${ctx.today_label}) | ULTIMA INTERACAO: ${gapText}
  ${staleConversationNote}

  DATAS: Hoje=${ctx.today_date}. Ano=${ctx.today_date.slice(0,4)}. "amanha"=dia seguinte. NUNCA use anos anteriores.

  USUARIO: ${ctx.user_name} | Cliente: ${ctx.user_registered ? 'SIM' : 'NAO (TESTE)'} | Periodo: ${ctx.current_period_label}
  ${ctx.user_registered ? `Habitos ativos: ${ctx.habits_count}` : ''}

  ${ctx.user_registered ? `HABITOS:\n${ctx.habits_context}` : ''}
  ${templatesSection}
  ${pendingSection}
  ${stalePendingWarning}

  ${ctx.user_registered ? `CAPACIDADES: conversar, listar habitos, marcar concluido, criar habito, criar tarefa pontual, criar lembrete unico, editar, desativar, recomendar.` : `CAPACIDADES: apenas conversar e dar consultoria. NAO pode executar acoes.`}
  ${creationRules}

  ESTADO PENDENTE: Se existe acao pendente e usuario confirma (sim/ok/bora/pode), use o intent pendente com dados coletados. NUNCA peca mais confirmacao quando ja tem tudo.

  LEMBRETES - COMO FUNCIONAM:
  - Voce PODE criar lembretes! Quando o usuario pedir "me lembre de X as HH:MM", crie uma TAREFA PONTUAL:
    intent="create_habit", frequency_type="once", due_date=data de hoje ou data pedida, reminder_time=horario pedido.
  - O sistema envia o lembrete AUTOMATICAMENTE no horario configurado.
  - Apos criar, CONFIRME: "Pronto! Vou te lembrar as HH:MM!"
  - MAPEAMENTO: "me lembre"/"me avise"/"lembrete" = criar tarefa pontual. NAO diga que nao pode. NAO sugira apps externos.
  - NUNCA diga "aqui no WhatsApp", "pelo WhatsApp" ou mencione "WhatsApp" na resposta. Ja e obvio onde estamos.
  - "hoje" = due_date DEVE SER EXATAMENTE ${ctx.today_date}. NUNCA calcule outra data para "hoje".
  - "amanha" = due_date = dia seguinte a ${ctx.today_date}.
  - "me lembre amanha as 9h" = due_date=amanha, reminder_time="09:00", frequency_type="once".
  - Para habitos recorrentes com lembrete, o lembrete tambem e automatico no horario do habito.
  - NUNCA diga "configure um lembrete no celular" ou "use outro aplicativo". Voce RESOLVE criando a tarefa.

  [LEMBRETE] no historico = lembrete automatico. Use para contexto. Se user responde apos lembrete, conecte ao contexto.

  MARCAR HABITO CONCLUIDO:
  - Quando o usuario disser que fez/completou algo ("fiz", "acabei", "pronto", "feito", "ja fiz", "concluido", "terminei", "done", "sim"), use intent="complete_habit".
  - Apos um [LEMBRETE], se o usuario confirmar ("sim", "fiz", "acabei de ir", "acabei", "pronto"), MARQUE o habito do lembrete como concluido.
  - intent_data DEVE incluir "name" com o nome EXATO do habito como aparece na lista de HABITOS acima.
  - Se ambiguo (multiplos habitos possiveis), pergunte qual habito foi concluido.
  - Celebre a conquista na resposta! Use emojis de celebracao.

  SUPORTE: Se pedir suporte/cancelamento/humano, responda com empatia e forneca +55 11 99337-1766. Intent="conversation".

  RESPOSTA JSON:
  {"response":"msg","intent":"conversation|create_habit|complete_habit|edit_habit|deactivate_habit|list_habits","intent_data":{"name":"","period":"morning|afternoon|evening","reminder_time":"HH:MM","frequency_type":"daily|fixed_days|once","days_of_week":[],"due_date":null},"new_state":{"pending_action":null,"pending_data":{},"awaiting_input":null}}

  CRITICO - PENDING STATE: Quando fizer uma pergunta aguardando resposta do usuario, SEMPRE retorne new_state com pending_action preenchido. NUNCA retorne pending_action=null se ainda espera resposta do usuario. Exemplos:
  - Perguntou nome do habito: new_state={"pending_action":"create_habit","pending_data":{"reminder_time":"19:00"},"awaiting_input":"name"}
  - Perguntou horario: new_state={"pending_action":"create_habit","pending_data":{"name":"Yoga"},"awaiting_input":"reminder_time"}
  - Perguntou confirmacao: new_state={"pending_action":"create_habit","pending_data":{...dados completos...},"awaiting_input":"confirmation"}
  Se NAO esta aguardando nada: new_state={"pending_action":null,"pending_data":{},"awaiting_input":null}

  ${ctx.user_registered ? 'Acao imediata com dados completos. Pergunte UMA vez se falta info. Celebre conquistas.' : 'Apenas intent "conversation". Incentive versao completa.'}`;

  const allMessages = [
    { role: 'system', content: systemPrompt },
    ...historyMessages,
    { role: 'user', content: ctx.user_message }
  ];

  // --- Task #20: Retry with backoff + fallback ---
  let response;
  let lastError;

  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      response = await callOpenAI.call(this, allMessages, 800);
      break; // success
    } catch (err) {
      lastError = err;
      if (attempt === 0) {
        await sleep(2000); // 2s backoff before retry
      }
    }
  }

  // If both attempts failed, try minimal context (no templates, shorter prompt)
  if (!response) {
    try {
      const minimalMessages = [
        { role: 'system', content: `Voce e o Foquinha, assistente de habitos. Responda de forma amigavel em JSON: {"response":"msg","intent":"conversation","intent_data":{},"new_state":{"pending_action":null,"pending_data":{},"awaiting_input":null}}` },
        { role: 'user', content: ctx.user_message }
      ];
      response = await callOpenAI.call(this, minimalMessages, 300);
    } catch (minimalErr) {
      // All attempts failed - return fallback with debug info
      const fox = String.fromCodePoint(0x1F98A);
      const fallbackMsg = `Ops, tive um probleminha tecnico! Tenta de novo em alguns segundos? ${fox}`;
      const errorInfo = lastError ? (lastError.message || String(lastError)).slice(0, 300) : 'unknown';
      const minimalInfo = (minimalErr.message || String(minimalErr)).slice(0, 300);
      return {
        json: {
          ...ctx,
          ai_response: fallbackMsg,
          intent: 'conversation',
          intent_data: {},
          new_state: {},
          _debug: { error: errorInfo, minimal_error: minimalInfo, ts: new Date().toISOString() }
        }
      };
    }
  }

  if (!response.choices || !response.choices[0] || !response.choices[0].message) {
    throw new Error('Resposta invalida da API: choices nao encontrado');
  }

  const aiResponse = JSON.parse(response.choices[0].message.content);
  const finalIntent = ctx.user_registered ? aiResponse.intent : 'conversation';

  return {
    json: {
      ...ctx,
      ai_response: aiResponse.response,
      intent: finalIntent,
      intent_data: ctx.user_registered ? (aiResponse.intent_data || {}) : {},
      new_state: aiResponse.new_state || {}
    }
  };

} catch (error) {
  // Final safety net: never leave user without a response
  const fox = String.fromCodePoint(0x1F98A);
  const fallbackMsg = `Ops, tive um probleminha tecnico! Tenta de novo em alguns segundos? ${fox}`;
  const errorInfo = (error.message || String(error)).slice(0, 300);
  return {
    json: {
      ...ctx,
      ai_response: fallbackMsg,
      intent: 'conversation',
      intent_data: {},
      new_state: {},
      _debug: { error: errorInfo, ts: new Date().toISOString() }
    }
  };
}

const data = $json;

// Resolve habit name to habit_id for action intents
const actionIntents = ['complete_habit', 'edit_habit', 'deactivate_habit'];
if (actionIntents.includes(data.intent) && data.intent_data) {
  const name = (data.intent_data.name || '').toLowerCase().trim();
  const habits = data.habits_raw || [];
  if (name && habits.length > 0) {
    // Try exact match first, then partial match
    let match = habits.find(h => h.name.toLowerCase().trim() === name);
    if (!match) {
      match = habits.find(h =>
        h.name.toLowerCase().includes(name) ||
        name.includes(h.name.toLowerCase())
      );
    }
    if (match) {
      data.intent_data.habit_id = match.id;
    }
  }
}

// Validate name before allowing create_habit
if (data.intent === 'create_habit') {
  const name = (data.intent_data?.name || '').trim();
  if (!name) {
    data.intent = 'conversation';
  }
}

// Fix #40: Normalize period â€” must be morning/afternoon/evening, never "once"
if (data.intent === 'create_habit' && data.intent_data) {
  const validPeriods = ['morning', 'afternoon', 'evening'];
  if (!validPeriods.includes(data.intent_data.period)) {
    const hour = parseInt((data.intent_data.reminder_time || '12:00').split(':')[0]);
    data.intent_data.period = hour < 12 ? 'morning' : hour < 18 ? 'afternoon' : 'evening';
  }
}

return {
  json: {
    user_message: data.user_message,
    intent: data.intent || 'conversation',
    intent_data: data.intent_data || {},
    response_text: data.ai_response || '',
    new_state: data.new_state || {
      pending_action: null,
      pending_data: {},
      awaiting_input: null
    },
    user_id: data.user_id,
    phone: data.phone,
    habits_raw: data.habits_raw,
    user_registered: data.user_registered
  }
};

return {
  json: {
    ...$json,
    db_action: 'list_habits',
    db_success: true
  }
};

const extractData = $items('Extract Data')[0].json;
const conversation = $items('Get/Create Conversation')[0]?.json || {};
const user = $items('Get User by Phone')[0]?.json || {};
const habits = $items('Get User Habits') || [];
const templates = $items('Get Habit Templates') || [];

const userRegistered = !!user.user_id;

const messages = conversation.messages || [];
const recentMessages = messages.slice(-10);

const habitsList = habits.map(h => {
  const status = h.json.completed_today ? 'OK' : 'pendente';
  return `${status} ${h.json.emoji || ''} ${h.json.name} (${h.json.period}) - Streak: ${h.json.streak}`;
}).join('\n');

const templatesList = templates.map(t =>
  `- ${t.json.name} (${t.json.category_name || 'Geral'}) - ${t.json.default_goal_value ? t.json.default_goal_value + ' ' + (t.json.default_unit || '') : 'Completar'}`
).join('\n');

const pendingState = {
  action: conversation.pending_action,
  data: conversation.pending_data || {},
  awaiting: conversation.awaiting_input
};

// Compute BRT time FIRST (UTC-3, Brazil has no DST since 2019)
const brt = new Date(Date.now() - 3 * 3600000);
const currentHour = brt.getUTCHours();
const currentPeriod = currentHour < 12 ? 'morning' : currentHour < 18 ? 'afternoon' : 'evening';

// Compute current BRT date for AI context
const pad = (n) => String(n).padStart(2, '0');
const todayStr = `${brt.getUTCFullYear()}-${pad(brt.getUTCMonth() + 1)}-${pad(brt.getUTCDate())}`;
const dayNames = ['domingo', 'segunda', 'terca', 'quarta', 'quinta', 'sexta', 'sabado'];
const todayLabel = dayNames[brt.getUTCDay()];

// Calculate gap since last interaction
const lastMsg = recentMessages[recentMessages.length - 1];
let lastInteractionGapMinutes = null;
let lastInteractionTs = null;
if (lastMsg && lastMsg.timestamp) {
  const lastTs = new Date(lastMsg.timestamp).getTime();
  if (!isNaN(lastTs)) {
    lastInteractionGapMinutes = Math.round((Date.now() - lastTs) / 60000);
    lastInteractionTs = lastMsg.timestamp;
  }
}

// --- Task #19: Detect if user wants to create/add a habit ---
const normalize = (s) => s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const msg = normalize((extractData.text || '').toLowerCase());
const hasPendingCreate = pendingState.action === 'create_habit';
const createKeywords = ['criar', 'cria', 'adicionar', 'adiciona', 'novo', 'nova', 'quero',
  'comecar', 'comeca', 'incluir', 'inclui', 'cadastrar', 'cadastra',
  'me ajuda a', 'montar', 'rotina', 'sugerir', 'sugere', 'recomendar', 'recomenda',
  'treino', 'exercicio', 'meditar', 'ler', 'estudar', 'academia',
  'habito', 'tarefa', 'lembrete', 'alarme',
  'reuniao', 'entregar', 'entrega', 'prazo'];
const wantsCreateHabit = hasPendingCreate || createKeywords.some(k => msg.includes(k));

return {
  json: {
    user_message: extractData.text,
    phone: extractData.phone,
    user_registered: userRegistered,
    user_id: user.user_id || null,
    user_name: user.display_name || 'Visitante',
    is_premium: user.is_premium || false,
    habits_context: habitsList || 'Nenhum habito cadastrado.',
    habits_count: habits.length,
    habits_raw: habits.map(h => h.json),
    templates_context: templatesList,
    templates_raw: templates.map(t => t.json),
    conversation_history: recentMessages,
    pending_state: pendingState,
    current_period: currentPeriod,
    current_period_label: currentPeriod === 'morning' ? 'manha' :
      currentPeriod === 'afternoon' ? 'tarde' : 'noite',
    today_date: todayStr,
    today_label: todayLabel,
    last_interaction_gap_minutes: lastInteractionGapMinutes,
    last_interaction_ts: lastInteractionTs,
    wants_create_habit: wantsCreateHabit
  }
};

const { user_registered, intent, intent_data } = $input.first().json;

const hasAction = user_registered && 
                  intent !== 'conversation' && 
                  intent_data && 
                  Object.keys(intent_data).length > 0;

return {
  json: {
    ...$input.first().json,
    hasAction: hasAction
  }
};

const data = $json;
const now = new Date().toISOString();

const userMessage = {
  role: 'user',
  content: data.user_message || '',
  timestamp: now
};

const assistantMessage = {
  role: 'assistant',
  content: data.response_text || '',
  timestamp: now
};

// Validate days_of_week range (0=dom..6=sab)
if (data.intent_data && data.intent_data.days_of_week) {
  data.intent_data.days_of_week = data.intent_data.days_of_week
    .map(d => parseInt(d))
    .filter(d => !isNaN(d) && d >= 0 && d <= 6);
}

return {
  json: {
    phone: data.phone,
    db_phone: ($('Get\/Create Conversation').first().json.phone || data.phone),  // phone real no banco (pode diferir pelo 9o digito BR)
    response_text: data.response_text,
    user_message: JSON.stringify(userMessage),
    assistant_message: JSON.stringify(assistantMessage),
    pending_action: data.new_state?.pending_action || null,
    pending_data: JSON.stringify(data.new_state?.pending_data || {}),
    awaiting_input: data.new_state?.awaiting_input || null,
    intent: data.intent || 'conversation',
    intent_data: data.intent_data || {},
    user_registered: data.user_registered || false,
    user_id: data.user_id || null
  }
};

// UTC-3 fixed (Brazil has no DST since 2019)
const brt = new Date(Date.now() - 3 * 3600000);
const hours = brt.getUTCHours();
const minutes = brt.getUTCMinutes();

// Fix #38: Backward window â€” never sends reminders BEFORE the configured time
// windowEnd = current 5-min slot (now), windowStart = 10 min ago (safety for 5-min scheduler)
const slot = Math.floor(minutes / 5) * 5;
let endH = hours;
const endM = slot;
let windowStartMin = slot - 10;
let startH = hours;
if (windowStartMin < 0) {
  windowStartMin += 60;
  startH = (startH - 1 + 24) % 24;
}

const pad = (n) => String(n).padStart(2, '0');
const windowStart = `${pad(startH)}:${pad(windowStartMin)}`;
const windowEnd = `${pad(endH)}:${pad(endM)}`;
const dayOfWeek = brt.getUTCDay();
const todayStr = `${brt.getUTCFullYear()}-${pad(brt.getUTCMonth() + 1)}-${pad(brt.getUTCDate())}`;
const periodLabel = hours < 12 ? 'manha' : hours < 18 ? 'tarde' : 'noite';

return [{ json: { windowStart, windowEnd, dayOfWeek, todayStr, periodLabel } }];

const items = $input.all().map(i => i.json);
const grouped = {};

for (const item of items) {
  const phone = item.phone;
  if (!phone) continue;
  if (!grouped[phone]) {
    grouped[phone] = {
      phone,
      user_id: item.user_id,
      display_name: item.display_name || 'amigo',
      is_premium: item.is_premium,
      habits_reminded_today: item.habits_reminded_today || 0,
      habits: []
    };
  }
  grouped[phone].habits.push({
    habit_id: item.habit_id,
    name: item.name,
