    source: item.source,
    effective_time: item.effective_time
  });
}

return Object.values(grouped).map(user => {
  const habits = user.habits;

  const habitsLines = habits.map(h => {
    const time = h.effective_time ? String(h.effective_time).slice(0,5) : '';
    let line = time ? `${time} ${h.emoji} ${h.name}` : `${h.emoji} ${h.name}`;
    if (h.streak >= 3) line += ` (streak: ${h.streak})`;
    if (h.frequency_type === 'once' && h.due_date) line += ' [HOJE - tarefa unica]';
    return line;
  });

  const maxStreak = Math.max(...habits.map(h => h.streak || 0), 0);
  const streakMilestone = maxStreak >= 30 ? '30+' :
    maxStreak >= 14 ? '14+' :
    maxStreak >= 7 ? '7+' : null;

  const isFirstReminder = user.habits_reminded_today === 0;

  return {
    json: {
      ...user,
      habit_ids: habits.map(h => h.habit_id),
      habit_count: habits.length,
      habits_text: habitsLines.join(String.fromCharCode(10)),
      max_streak: maxStreak,
      streak_milestone: streakMilestone,
      is_first_reminder: isFirstReminder
    },
    pairedItem: { item: 0 }
  };
});

