const items = $input.all();
const results = [];

for (const item of items) {
  let text;
  try {
    const cr = $('Check Create Result').first();
    if (cr && cr.json?.response_text !== undefined) text = cr.json.response_text;
  } catch(e) {}
  if (!text) text = $('Format DB Parameters').first().json.response_text || '';
  const phone = $('Format DB Parameters').first().json.phone || '';

  // Se nao tem texto, envia vazio
  if (!text) {
    results.push({ json: { phone, chunk: text, chunkIndex: 0, totalChunks: 1 } });
    continue;
  }

  // Se tem \n\n, SEMPRE splitta (cada \n\n = bolha separada no WhatsApp)
  const hasParaBreaks = text.includes('\n\n');

  if (!hasParaBreaks) {
    // Sem \n\n: mensagem unica (mesmo que longa, AI decidiu nao quebrar)
    results.push({ json: { phone, chunk: text, chunkIndex: 0, totalChunks: 1 } });
    continue;
  }

  // Split em cada \n\n
  const paragraphs = text.split(/\n\n+/).map(p => p.trim()).filter(p => p);

  // Merge SOMENTE fragmentos < 20 chars (emoji sozinho, "Ok", etc)
  const MIN_MERGE = 20;
  const chunks = [];
  for (const p of paragraphs) {
    if (chunks.length > 0 && p.length < MIN_MERGE) {
      chunks[chunks.length - 1] += '\n\n' + p;
    } else {
      chunks.push(p);
    }
  }

  // Limite: max 5 bolhas por vez (seguranca anti-spam)
  const limited = chunks.slice(0, 5);

  for (let i = 0; i < limited.length; i++) {
    results.push({ json: { phone, chunk: limited[i], chunkIndex: i, totalChunks: limited.length } });
  }
}

return results;

