  if (!phone) continue;
  if (!grouped[phone]) {
    grouped[phone] = {
      phone,
      user_id: item.user_id,
      display_name: item.display_name || 'amigo',
      is_premium: item.is_premium,
      habits_reminded_today: item.habits_reminded_today || 0,
      habits: []
    };
  }
  grouped[phone].habits.push({
    habit_id: item.habit_id,
    name: item.name,
    emoji: item.emoji || '',
    streak: item.streak || 0,
    period: item.period,
    category: item.category || '',
    frequency_type: item.frequency_type,
    due_date: item.due_date,
    source: item.source,
    effective_time: item.effective_time
  });
}

