// Format Morning Summary — Fix: usando String.fromCodePoint para evitar mojibake
const SUN    = String.fromCodePoint(0x2600, 0xFE0F); // ☀️
const MUSCLE = String.fromCodePoint(0x1F4AA);        // 💪
const ROCKET = String.fromCodePoint(0x1F680);        // 🚀
const SPARK  = String.fromCodePoint(0x2728);         // ✨
const FIRE   = String.fromCodePoint(0x1F525);        // 🔥

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const name = data.display_name || 'amigo(a)';
  const habits = typeof data.habits_today === 'string'
    ? JSON.parse(data.habits_today)
    : data.habits_today;
  const count = data.habit_count || habits.length;

  // Sort by reminder_time (chronological)
  const sorted = habits.slice().sort((a, b) => {
    const ta = a.reminder_time ? String(a.reminder_time).slice(0,5) : '09:00';
    const tb = b.reminder_time ? String(b.reminder_time).slice(0,5) : '09:00';
    return ta.localeCompare(tb);
  });

  const lines = [`Bom dia, ${name}! ${SUN} Seu plano pra hoje:\n`];

  for (const h of sorted) {
    const time = h.reminder_time ? String(h.reminder_time).slice(0,5) : '\u2014';
    lines.push(`${time} ${h.emoji || ''} ${h.name}`);
  }

  // Motivational closer
  const closers = [
    `S\u00E3o ${count} h\u00E1bitos hoje. Bora! ${MUSCLE}`,
    `${count} h\u00E1bitos te esperando. Vamos nessa! ${ROCKET}`,
    `Hoje s\u00E3o ${count} h\u00E1bitos. Voc\u00EA consegue! ${SPARK}`,
    `${count} h\u00E1bitos no plano de hoje. Partiu! ${FIRE}`
  ];
  const closer = closers[Math.floor(Math.random() * closers.length)];
  lines.push(`\n${closer}`);

  const message = lines.join('\n');

  results.push({
    json: {
      user_id: data.user_id,
      phone: data.phone,
      display_name: name,
      message,
      message_type: 'morning_summary'
    }
  });
}

return results;

// Format Evening Recap — template-based, no AI call
// Fix: usando String.fromCodePoint para evitar mojibake de emojis
const MOON   = String.fromCodePoint(0x1F319); // 🌙
const CHECK  = String.fromCodePoint(0x2705);   // ✅
const EMPTY  = String.fromCodePoint(0x2B1C);   // ⬜
const TROPHY = String.fromCodePoint(0x1F3C6);  // 🏆
const STAR   = String.fromCodePoint(0x2B50);   // ⭐
const PARTY  = String.fromCodePoint(0x1F389);  // 🎉
const FLEX   = String.fromCodePoint(0x1F4AA);  // 💪
const FIRE   = String.fromCodePoint(0x1F525);  // 🔥
const SPARK  = String.fromCodePoint(0x2728);   // ✨
const GLOW   = String.fromCodePoint(0x1F31F);  // 🌟
const DIZZY  = String.fromCodePoint(0x1F4AB);  // 💫
const SMILE  = String.fromCodePoint(0x1F60A);  // 😊
const SUNR   = String.fromCodePoint(0x1F305);  // 🌅
const BLUE   = String.fromCodePoint(0x1F499);  // 💙
const FLOWER = String.fromCodePoint(0x1F33B);  // 🌻

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const name = data.display_name || 'amigo(a)';
  const habits = typeof data.habits_today === 'string'
    ? JSON.parse(data.habits_today)
    : data.habits_today;
  const total = data.total_habits || habits.length;
  const completed = data.completed_count || 0;

  const lines = [`Boa noite, ${name}! ${MOON} Resumo do dia:\n`];

  for (const h of habits) {
    const done = h.completed === true || h.completed === 't';
    const icon = done ? CHECK : EMPTY;
    const status = done ? 'feito!' : 'pendente';
    const emoji = h.emoji || '';
    lines.push(`${icon} ${emoji} ${h.name} — ${status}`);
  }

  // Summary line
  const rate = total > 0 ? Math.round((completed / total) * 100) : 0;

  let closerMsg;
  if (rate === 100) {
    const perfect = [
      `Dia perfeito! Você arrasou! ${TROPHY}`,
      `Todos concluídos! Que dia incrível! ${STAR}`,
      `100%! Orgulho de você! ${PARTY}`
    ];
    closerMsg = perfect[Math.floor(Math.random() * perfect.length)];
  } else if (rate >= 70) {
    const great = [
      `Mandou muito bem hoje! ${FLEX}`,
      `Ótimo progresso! Continue assim! ${FIRE}`,
      `Dia produtivo! Parabéns! ${SPARK}`
    ];
    closerMsg = great[Math.floor(Math.random() * great.length)];
  } else if (rate >= 40) {
    const ok = [
      `Cada hábito feito conta! ${GLOW}`,
      `Progresso é progresso! Amanhã a gente continua ${DIZZY}`,
      `Bom começo! Amanhã pode ser ainda melhor ${SMILE}`
    ];
    closerMsg = ok[Math.floor(Math.random() * ok.length)];
  } else {
    const low = [
      `Amanhã é um novo dia! ${SUNR}`,
      `Descansa bem, amanhã a gente retoma! ${BLUE}`,
      `Tudo bem, cada dia é uma chance nova ${FLOWER}`
    ];
    closerMsg = low[Math.floor(Math.random() * low.length)];
  }

  lines.push(`\n${completed}/${total} concluídos. ${closerMsg}`);

  const message = lines.join('\n');

  results.push({
    json: {
      user_id: data.user_id,
      phone: data.phone,
      display_name: name,
      message,
      message_type: 'evening_recap'
    }
  });
}

return results;

// Format Weekly Progress — Fix: usando String.fromCodePoint para evitar mojibake
const CHART  = String.fromCodePoint(0x1F4CA); // 📊
const CAL    = String.fromCodePoint(0x1F4C5); // 📅
const TROPHY = String.fromCodePoint(0x1F3C6); // 🏆
const FIRE   = String.fromCodePoint(0x1F525); // 🔥
const BARS   = String.fromCodePoint(0x1F4C8); // 📈
const ROCKET = String.fromCodePoint(0x1F680); // 🚀
const STAR   = String.fromCodePoint(0x2B50);  // ⭐
const PARTY  = String.fromCodePoint(0x1F389); // 🎉
const MUSCLE = String.fromCodePoint(0x1F4AA); // 💪
const SPARK  = String.fromCodePoint(0x2728);  // ✨
const DIZZY  = String.fromCodePoint(0x1F4AB); // 💫
const SMILE  = String.fromCodePoint(0x1F60A); // 😊
const PLANT  = String.fromCodePoint(0x1F331); // 🌱
const BLUE   = String.fromCodePoint(0x1F499); // 💙
const SEAL   = String.fromCodePoint(0x1F9AD); // 🦭

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const name = data.display_name || 'amigo(a)';
  const totalHabits = data.total_active_habits || 0;
  const completions = data.completions_this_week || 0;
  const bestStreak = data.best_streak || 0;
  const bestStreakHabit = data.best_streak_habit || '';
  const bestStreakEmoji = data.best_streak_emoji || '';

  const possible = data.expected_completions_this_week || (totalHabits * 7);
  const rate = possible > 0 ? Math.min(Math.round((completions / possible) * 100), 100) : 0;

  const todayStr = $('Get BRT Time').first().json.todayStr;
  const today = new Date(todayStr + 'T12:00:00');
  const weekStart = new Date(today);
  weekStart.setDate(today.getDate() - 6);
  const fmtDate = (d) => {
    return String(d.getDate()).padStart(2, '0') + '/' + String(d.getMonth() + 1).padStart(2, '0');
  };
  const weekRange = `${fmtDate(weekStart)} a ${fmtDate(today)}`;

  const lines = [`Semana encerrada, ${name}! ${CHART}\n`];
  lines.push(`${CAL} Semana de ${weekRange}`);
  lines.push(`${TROPHY} ${completions} h\u00E1bitos conclu\u00EDdos essa semana`);

  if (bestStreak > 0 && bestStreakHabit) {
    lines.push(`${FIRE} Melhor streak: ${bestStreak} dias em ${bestStreakEmoji} ${bestStreakHabit}`.trim());
  }

  lines.push(`${BARS} Taxa de conclus\u00E3o: ~${rate}%`);

  let closer;
  if (rate >= 80) {
    const great = [
      `Semana incr\u00EDvel! Continue assim! ${ROCKET}`,
      `Voc\u00EA est\u00E1 voando! Orgulho! ${STAR}`,
      `Consist\u00EAncia \u00E9 tudo! Parab\u00E9ns! ${PARTY}`
    ];
    closer = great[Math.floor(Math.random() * great.length)];
  } else if (rate >= 50) {
    const good = [
      `Bom progresso! Semana que vem pode ser ainda melhor ${MUSCLE}`,
      `Metade ou mais! Continue firme! ${FIRE}`,
      `Progresso consistente. Vamos em frente! ${SPARK}`
    ];
    closer = good[Math.floor(Math.random() * good.length)];
  } else if (rate > 0) {
    const ok = [
      `Cada h\u00E1bito conclu\u00EDdo \u00E9 uma vit\u00F3ria! ${DIZZY}`,
      `O importante \u00E9 n\u00E3o parar. Vamos juntos! ${SMILE}`,
      `Semana que vem a gente manda ver! ${SMILE}`
    ];
    closer = ok[Math.floor(Math.random() * ok.length)];
  } else {
    const start = [
      `Essa semana \u00E9 uma nova chance! Vamos come\u00E7ar? ${PLANT}`,
      `Bora recome\u00E7ar juntos essa semana? ${BLUE}`,
      `Estou aqui pra te ajudar! Vamos nessa? ${SEAL}`
    ];
    closer = start[Math.floor(Math.random() * start.length)];
  }

  lines.push(`\n${closer}`);

  const message = lines.join('\n');

  results.push({
    json: {
      user_id: data.user_id,
      phone: data.phone,
      display_name: name,
      message,
      message_type: 'weekly_progress'
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  let text;
  try {
    const cr = $('Check Create Result').first();
    if (cr && cr.json?.response_text !== undefined) text = cr.json.response_text;
  } catch(e) {}
  if (!text) text = $('Format DB Parameters').first().json.response_text || '';
  const phone = $('Format DB Parameters').first().json.phone || '';

  // Se nao tem texto, envia vazio
  if (!text) {
    results.push({ json: { phone, chunk: text, chunkIndex: 0, totalChunks: 1 } });
    continue;
  }

  // Se tem \n\n, SEMPRE splitta (cada \n\n = bolha separada no WhatsApp)
  const hasParaBreaks = text.includes('\n\n');

  if (!hasParaBreaks) {
    // Sem \n\n: mensagem unica (mesmo que longa, AI decidiu nao quebrar)
    results.push({ json: { phone, chunk: text, chunkIndex: 0, totalChunks: 1 } });
    continue;
  }

  // Split em cada \n\n
  const paragraphs = text.split(/\n\n+/).map(p => p.trim()).filter(p => p);

  // Merge SOMENTE fragmentos < 20 chars (emoji sozinho, "Ok", etc)
  const MIN_MERGE = 20;
  const chunks = [];
  for (const p of paragraphs) {
    if (chunks.length > 0 && p.length < MIN_MERGE) {
      chunks[chunks.length - 1] += '\n\n' + p;
    } else {
      chunks.push(p);
    }
  }

  // Limite: max 5 bolhas por vez (seguranca anti-spam)
  const limited = chunks.slice(0, 5);

  for (let i = 0; i < limited.length; i++) {
    results.push({ json: { phone, chunk: limited[i], chunkIndex: i, totalChunks: limited.length } });
  }
}

return results;

