        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: [notifRow],
      json: true
    });
  } catch (e) {
    // Log error but continue
  }

  // 2. Save to whatsapp_conversations
