          'Authorization': 'Bearer ' + SUPABASE_KEY,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: { messages: msgs },
        json: true
      });
    }
  } catch (e) {
    // Log error but continue
  }

  results.push({ json: { ...data, log_status: 'success' } });
}

return results;

